<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Discovery — 24 Exploring Bots</title>
<style>
  :root { --bg:#0f1117; --panel:#1b1f2a; --ink:#e8ecf4; --accent:#5cc8ff; }
  * { box-sizing: border-box; }
  body {
    margin: 0; background: var(--bg); color: var(--ink);
    font-family: "Segoe UI", system-ui, sans-serif;
    display: flex; flex-direction: column; align-items: center;
    padding: 18px; min-height: 100vh;
  }
  h1 { font-size: 18px; font-weight: 600; margin: 4px 0 12px; letter-spacing: .3px; }
  .bar {
    display: flex; gap: 14px; align-items: center; flex-wrap: wrap;
    background: var(--panel); padding: 10px 16px; border-radius: 12px;
    margin-bottom: 14px; box-shadow: 0 2px 10px rgba(0,0,0,.4);
  }
  .stat { font-size: 14px; }
  .stat b { color: var(--accent); font-variant-numeric: tabular-nums; }
  #reset {
    background: var(--accent); color: #05243a; border: none; cursor: pointer;
    font-weight: 700; font-size: 14px; padding: 8px 16px; border-radius: 8px;
  }
  #reset:hover { filter: brightness(1.1); }
  #maze {
    background: #12151d; padding: 10px; border-radius: 12px;
    box-shadow: 0 6px 24px rgba(0,0,0,.5); line-height: 0;
  }
  canvas { display: block; border-radius: 6px; }
  .hint { font-size: 12px; opacity: .6; margin-top: 12px; max-width: 620px; text-align:center; }
</style>
</head>
<body>
  <h1>Maze Discovery — 24 bots exploring (Tremaux / DFS)</h1>
  <div class="bar">
    <div class="stat">Reached exit: <b id="completed">0</b> / 24</div>
    <div class="stat">Timer (ticks): <b id="timer">0</b></div>
    <button id="reset">New Maze</button>
  </div>
  <div id="maze">
    <canvas id="cv" width="600" height="600"></canvas>
  </div>
  <div class="hint">
    Each bot knows only its current cell. It senses walls on entry, prefers a distinct
    seeded direction order, and backtracks out of dead branches (never traversing a
    passage more than twice). No bot ever computes a global path to the exit.
  </div>

<script>
(function(){
  "use strict";

  // ---------- config ----------
  const rows = 15, cols = 15;
  const CANVAS = 600;
  const cs = Math.floor(CANVAS / cols);
  const stepDuration = 100; // ms per tick when auto-running (visual only)

  const D = {
    n: { dr:-1, dc:0, opp:'s' },
    e: { dr:0,  dc:1, opp:'w' },
    s: { dr:1,  dc:0, opp:'n' },
    w: { dr:0,  dc:-1, opp:'e' }
  };

  // ---------- seeded RNG ----------
  function mulberry32(a){
    return function(){
      a |= 0; a = (a + 0x6D2B79F5) | 0;
      let t = Math.imul(a ^ (a >>> 15), 1 | a);
      t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }

  // ---------- deterministic direction permutations ----------
  function permutations(arr){
    if (arr.length <= 1) return [arr.slice()];
    const res = [];
    for (let i = 0; i < arr.length; i++){
      const rest = arr.slice(0,i).concat(arr.slice(i+1));
      for (const p of permutations(rest)) res.push([arr[i]].concat(p));
    }
    return res;
  }
  const dirPerms = permutations(['n','e','s','w']); // exactly 24 distinct orders

  // ---------- maze generation (recursive backtracker => perfect maze) ----------
  function generateMaze(rng){
    const m = [];
    for (let r = 0; r < rows; r++){
      m.push([]);
      for (let c = 0; c < cols; c++) m[r].push({ n:true, e:true, s:true, w:true });
    }
    const visited = Array.from({length:rows}, () => Array(cols).fill(false));
    const stack = [{ r:0, c:0 }];
    visited[0][0] = true;
    const dirs = ['n','e','s','w'];
    while (stack.length){
      const cur = stack[stack.length-1];
      const opts = [];
      for (const d of dirs){
        const nr = cur.r + D[d].dr, nc = cur.c + D[d].dc;
        if (nr>=0 && nr<rows && nc>=0 && nc<cols && !visited[nr][nc]) opts.push(d);
      }
      if (opts.length === 0){ stack.pop(); continue; }
      const d = opts[Math.floor(rng() * opts.length)];
      const nr = cur.r + D[d].dr, nc = cur.c + D[d].dc;
      m[cur.r][cur.c][d] = false;
      m[nr][nc][D[d].opp] = false;
      visited[nr][nc] = true;
      stack.push({ r:nr, c:nc });
    }
    return m;
  }

  // ---------- state ----------
  let maze, spawn, exit, bots, elapsed, currentSeed;

  function reset(seed){
    currentSeed = (seed === undefined || seed === null)
      ? Math.floor(Math.random() * 0x7fffffff)
      : (seed >>> 0);
    const rng = mulberry32(currentSeed);
    maze  = generateMaze(rng);
    spawn = { r:0, c:0 };
    exit  = { r:rows-1, c:cols-1 };
    elapsed = 0;
    bots = [];
    for (let i = 0; i < 24; i++){
      bots.push({
        id: i,
        r: spawn.r, c: spawn.c,
        fromR: spawn.r, fromC: spawn.c,
        order: dirPerms[i % 24],
        visited: new Set([spawn.r + ',' + spawn.c]),
        stack: [{ r:spawn.r, c:spawn.c }],
        path: [{ r:spawn.r, c:spawn.c }],
        deadEnds: [],
        finishTick: null,
        done: false,
        color: 'hsl(' + Math.floor(i * 360 / 24) + ',85%,58%)'
      });
    }
    lastStepWall = nowMs();
  }

  // ---------- simulation ----------
  function allDone(){
    for (const b of bots) if (!b.done) return false;
    return true;
  }

  // One bot advances exactly one cell using only local knowledge (DFS/Tremaux).
  function botStep(bot, tick){
    const r = bot.r, c = bot.c;
    const w = maze[r][c]; // walls sensed on entry to this cell
    for (const dir of bot.order){
      if (!w[dir]){ // there is a passage this way
        const nr = r + D[dir].dr, nc = c + D[dir].dc;
        const key = nr + ',' + nc;
        if (!bot.visited.has(key)){ // an unexplored neighbour: go forward
          bot.fromR = r; bot.fromC = c;
          bot.r = nr; bot.c = nc;
          bot.visited.add(key);
          bot.stack.push({ r:nr, c:nc });
          bot.path.push({ r:nr, c:nc });
          if (nr === exit.r && nc === exit.c){ bot.done = true; bot.finishTick = tick; }
          return;
        }
      }
    }
    // No unexplored passage from here: this branch is dead -> record & backtrack.
    bot.deadEnds.push({ r:r, c:c });
    bot.stack.pop();
    if (bot.stack.length > 0){
      const p = bot.stack[bot.stack.length-1];
      bot.fromR = r; bot.fromC = c;
      bot.r = p.r; bot.c = p.c;
      bot.path.push({ r:p.r, c:p.c }); // backtracking still "enters" the parent cell
    } else {
      // Unreachable in a connected perfect maze; fail-safe so we never spin forever.
      bot.done = true; bot.finishTick = tick;
    }
  }

  // Advance the whole simulation by exactly one tick. Pure/deterministic.
  function stepOnce(){
    if (allDone()) return;          // frozen: timer & elapsed no longer change
    elapsed += 1;
    for (const b of bots){
      if (!b.done) botStep(b, elapsed);
    }
  }

  // ---------- rendering ----------
  const cv = document.getElementById('cv');
  const ctx = cv.getContext('2d');
  const elCompleted = document.getElementById('completed');
  const elTimer = document.getElementById('timer');
  cv.width = cols * cs; cv.height = rows * cs;

  function nowMs(){
    return (typeof performance !== 'undefined' && performance.now)
      ? performance.now() : Date.now();
  }
  function clamp(v,a,b){ return v < a ? a : (v > b ? b : v); }

  function draw(interp){
    ctx.clearRect(0,0,cv.width,cv.height);

    // spawn & exit markers
    ctx.fillStyle = 'rgba(90,200,120,0.35)';
    ctx.fillRect(spawn.c*cs+2, spawn.r*cs+2, cs-4, cs-4);
    ctx.fillStyle = 'rgba(255,90,110,0.40)';
    ctx.fillRect(exit.c*cs+2, exit.r*cs+2, cs-4, cs-4);

    // walls
    ctx.strokeStyle = '#8fa6c9';
    ctx.lineWidth = 2;
    ctx.lineCap = 'round';
    ctx.beginPath();
    for (let r = 0; r < rows; r++){
      for (let c = 0; c < cols; c++){
        const x = c*cs, y = r*cs, w = maze[r][c];
        if (w.n){ ctx.moveTo(x, y);       ctx.lineTo(x+cs, y); }
        if (w.w){ ctx.moveTo(x, y);       ctx.lineTo(x, y+cs); }
        if (w.e){ ctx.moveTo(x+cs, y);    ctx.lineTo(x+cs, y+cs); }
        if (w.s){ ctx.moveTo(x, y+cs);    ctx.lineTo(x+cs, y+cs); }
      }
    }
    ctx.stroke();

    // bots (smoothly interpolated, slightly fanned so overlaps stay visible)
    const rad = cs * 0.26;
    for (const b of bots){
      const dr = b.fromR + (b.r - b.fromR) * interp;
      const dc = b.fromC + (b.c - b.fromC) * interp;
      const ang = (b.id / 24) * Math.PI * 2;
      const off = cs * 0.10;
      const cx = (dc + 0.5) * cs + Math.cos(ang) * off;
      const cy = (dr + 0.5) * cs + Math.sin(ang) * off;
      ctx.beginPath();
      ctx.arc(cx, cy, rad, 0, Math.PI*2);
      ctx.fillStyle = b.color;
      ctx.globalAlpha = b.done ? 1 : 0.92;
      ctx.fill();
      ctx.globalAlpha = 1;
      ctx.lineWidth = 1.5;
      ctx.strokeStyle = b.done ? '#ffffff' : 'rgba(0,0,0,0.45)';
      ctx.stroke();
    }
  }

  function updateHud(){
    let done = 0;
    for (const b of bots) if (b.done) done++;
    elCompleted.textContent = String(done);
    elTimer.textContent = String(elapsed);
  }

  // ---------- main loop (stepping is time-gated; rendering interpolates) ----------
  let lastStepWall = nowMs();
  function frame(now){
    if (!allDone() && (now - lastStepWall) >= stepDuration){
      stepOnce();
      lastStepWall = now;
    }
    const interp = clamp((now - lastStepWall) / stepDuration, 0, 1);
    draw(interp);
    updateHud();
    requestAnimationFrame(frame);
  }

  // ---------- public scripting API ----------
  window.game = {
    tick: function(n){
      n = Math.max(0, Math.floor(n || 0));
      for (let i = 0; i < n; i++) stepOnce();
      lastStepWall = nowMs(); // let the final move animate for viewers
    },
    reset: function(seed){ reset(seed); },
    get elapsed(){ return elapsed; },
    get size(){ return { rows: rows, cols: cols }; },
    get spawn(){ return { r: spawn.r, c: spawn.c }; },
    get exit(){ return { r: exit.r, c: exit.c }; },
    walls: function(r, c){
      const w = maze[r][c];
      return { n: w.n, e: w.e, s: w.s, w: w.w };
    },
    get bots(){ return bots; }
  };

  // ---------- wire up UI ----------
  document.getElementById('reset').addEventListener('click', function(){ reset(); });

  // ---------- boot ----------
  reset();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
